member.example:
Bind a DebugLogBinder using a serialized field — the binder logs every incoming value to the Unity console.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private DebugLogBinder _debugLog;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _message;
    }
